@startuml
skinparam ClassBox {
    fontname "Helvetica"
    fontcolor "black"
    backgroundcolor "#f5f5f5"
    borderstyle solid
    bordercolor "#cccccc"
    style fill
}
skinparam Actor {
    fontname "Helvetica"
    fontcolor "black"
    backgroundcolor "#f5f5f5"
    borderstyle solid
    bordercolor "#cccccc"
    style fill
}
skinparam Relationship {
    fontname "Helvetica"
    fontcolor "black"
    style solid
    style fill
}
skinparam LinkLabel {
    fontname "Helvetica"
    fontcolor "black"
    style solid
    style fill
}

class Person {
    +id: Long
    +firstName: String
    +lastName: String
    +telNr: String
}

class Booking {
    +id: Long
    +person: Person
    +trip: Trip
}

class Trip {
    +id: Long
    +destination: Destination
    +bus: Bus
}

class Bus {
    +id: Long
    +seats: int
}

class Destination {
    +id: Long
    +street: String
    +streetNo: int
    +place: String
    +zip: int
}

Person --> Booking : bucht Reise (Trip)
Booking --> Trip : hat Buchungen
Trip --> Bus : Reise wird mit Bus durchgeführt
Trip --> Destination : Reise geht nach

@enduml
